   104	static inline void cmult(int16x8_t a,int16x8_t b, int32x4_t *re32, int32x4_t *im32) __attribute__((always_inline));
   105	static inline void cmult(int16x8_t a,int16x8_t b, int32x4_t *re32, int32x4_t *im32)
   106	{
   107	  int32x4_t ab_re0,ab_re1,ab_im0,ab_im1;
   108	  int16x8_t bflip = vrev32q_s16(b);
   109	  int16x8_t bconj = vmulq_s16(b,*(int16x8_t *)reflip);
   110	  int16x4_t al,ah,bcl,bch,bfl,bfh;
   111	  int32x2_t abr0l,abr0h,abr1l,abr1h,abi0l,abi0h,abi1l,abi1h;
   112	
   113	  al  = vget_low_s16(a);      ah = vget_high_s16(a);
   114	  bcl = vget_low_s16(bconj);  bch = vget_high_s16(bconj);
   115	  bfl = vget_low_s16(bflip);  bfh = vget_high_s16(bflip);
   116	
   117	  ab_re0 = vmull_s16(al,bcl);
   118	  ab_re1 = vmull_s16(ah,bch);
   119	  ab_im0 = vmull_s16(al,bfl);
   120	  ab_im1 = vmull_s16(ah,bfh);
   121	  abr0l = vget_low_s32(ab_re0); abr0h = vget_high_s32(ab_re0);
   122	  abr1l = vget_low_s32(ab_re1); abr1h = vget_high_s32(ab_re1);
   123	  abi0l = vget_low_s32(ab_im0); abi0h = vget_high_s32(ab_im0);
   124	  abi1l = vget_low_s32(ab_im1); abi1h = vget_high_s32(ab_im1);
   125	
   126	  *re32 = vcombine_s32(vpadd_s32(abr0l,abr0h),
   127	                       vpadd_s32(abr1l,abr1h));
   128	  *im32 = vcombine_s32(vpadd_s32(abi0l,abi0h),
   129	                       vpadd_s32(abi1l,abi1h));
   130	}
